from functools import wraps
from flask import Flask, render_template, request, redirect, url_for, session, flash

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not session.get('logged_in'):
            flash('Bu sayfayı görüntülemek için giriş yapmanız gerekiyor.', 'warning')
            return redirect(url_for('login', next=request.url))
        return f(*args, **kwargs)
    return decorated_function

app = Flask(__name__)
app.secret_key = 'cok_gizli_anahtar_burada_olmali_ve_uretilmeli' # Güvenlik için bu anahtarı değiştirmelisiniz!

@app.route('/')
def home():
    if session.get('logged_in'):
        return '<h1>Ana Sayfa</h1><p>Giriş Yaptınız! <a href="/dashboard">Panel</a> | <a href="/logout">Çıkış Yap</a></p>'
    return '<h1>Ana Sayfa</h1><p>Giriş Yapmadınız. <a href="/login">Giriş Yap</a> | <a href="/dashboard">Panele Git (korumalı)</a></p>'

@app.route('/login', methods=['GET', 'POST'])
def login():
    if session.get('logged_in'):
        flash('Zaten giriş yapmış durumdasınız.', 'info')
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')

        # Basit bir örnek doğrulama, gerçek uygulamada veritabanı kullanılmalı.
        if username == 'admin' and password == 'password':
            session['logged_in'] = True
            flash('Başarıyla giriş yaptınız!', 'success')
            next_url = request.args.get('next')
            return redirect(next_url or url_for('dashboard'))
        else:
            flash('Hatalı kullanıcı adı veya parola.', 'danger')

    # Giriş formu için HTML
    return '''
